80	export async function sendMessageNextcloudTalk(
81	  to: string,
82	  text: string,
83	  opts: NextcloudTalkSendOpts = {},
84	): Promise<NextcloudTalkSendResult> {
85	  const { cfg, account, baseUrl, secret } = resolveNextcloudTalkSendContext(opts);
86	  const roomToken = normalizeRoomToken(to);
87	
88	  if (!text?.trim()) {
89	    throw new Error("Message must be non-empty for Nextcloud Talk sends");
90	  }
91	
92	  const tableMode = resolveMarkdownTableMode({
93	    cfg,
94	    channel: "nextcloud-talk",
95	    accountId: account.accountId,
96	  });
97	  const message = convertMarkdownTables(text.trim(), tableMode);
98	
99	  const body: Record<string, unknown> = {
100	    message,
101	  };
102	  if (opts.replyTo) {
103	    body.replyTo = opts.replyTo;
104	  }
105	  const bodyStr = JSON.stringify(body);
106	
107	  // Nextcloud Talk verifies signature against the extracted message text,
108	  // not the full JSON body. See ChecksumVerificationService.php:
109	  //   hash_hmac('sha256', $random . $data, $secret)
110	  // where $data is the "message" parameter, not the raw request body.
111	  const { random, signature } = generateNextcloudTalkSignature({
112	    body: message,
113	    secret,
114	  });
115	
116	  const url = `${baseUrl}/ocs/v2.php/apps/spreed/api/v1/bot/${roomToken}/message`;
117	
118	  const { response, release } = await fetchWithSsrFGuard({
119	    url,
120	    init: {
121	      method: "POST",
122	      headers: {
123	        "Content-Type": "application/json",
124	        "OCS-APIRequest": "true",
125	        "X-Nextcloud-Talk-Bot-Random": random,
126	        "X-Nextcloud-Talk-Bot-Signature": signature,
127	      },
128	      body: bodyStr,
129	    },
130	    auditContext: "nextcloud-talk-send",
131	    policy: account.config?.allowPrivateNetwork ? { allowPrivateNetwork: true } : undefined,
132	  });
133	
134	  try {
135	    if (!response.ok) {
136	      const errorBody = await response.text().catch(() => "");
137	      const status = response.status;
138	      let errorMsg = `Nextcloud Talk send failed (${status})`;
139	
140	      if (status === 400) {
141	        errorMsg = `Nextcloud Talk: bad request - ${errorBody || "invalid message format"}`;
142	      } else if (status === 401) {
143	        errorMsg = "Nextcloud Talk: authentication failed - check bot secret";
144	      } else if (status === 403) {
145	        errorMsg = "Nextcloud Talk: forbidden - bot may not have permission in this room";
146	      } else if (status === 404) {
147	        errorMsg = `Nextcloud Talk: room not found (token=${roomToken})`;
148	      } else if (errorBody) {
149	        errorMsg = `Nextcloud Talk send failed: ${errorBody}`;
150	      }
151	
152	      throw new Error(errorMsg);
153	    }
154	
155	    let messageId = "unknown";
156	    let timestamp: number | undefined;
157	    try {
158	      const data = (await response.json()) as {
159	        ocs?: {
160	          data?: {
161	            id?: number | string;
162	            timestamp?: number;
163	          };
164	        };
165	      };
166	      if (data.ocs?.data?.id != null) {
167	        messageId = String(data.ocs.data.id);
168	      }
169	      if (typeof data.ocs?.data?.timestamp === "number") {
170	        timestamp = data.ocs.data.timestamp;
171	      }
172	    } catch {
173	      // Response parsing failed, but message was sent.
174	    }
175	
176	    if (opts.verbose) {
177	      console.log(`[nextcloud-talk] Sent message ${messageId} to room ${roomToken}`);
178	    }
179	
180	    recordNextcloudTalkOutboundActivity(account.accountId);
181	
182	    return { messageId, roomToken, timestamp };
183	  } finally {
184	    await release();
185	  }
186	}
