188	export async function sendReactionNextcloudTalk(
189	  roomToken: string,
190	  messageId: string,
191	  reaction: string,
192	  opts: Omit<NextcloudTalkSendOpts, "replyTo"> = {},
193	): Promise<{ ok: true }> {
194	  const { account, baseUrl, secret } = resolveNextcloudTalkSendContext(opts);
195	  const normalizedToken = normalizeRoomToken(roomToken);
196	
197	  const body = JSON.stringify({ reaction });
198	  // Sign only the reaction string, not the full JSON body
199	  const { random, signature } = generateNextcloudTalkSignature({
200	    body: reaction,
201	    secret,
202	  });
203	
204	  const url = `${baseUrl}/ocs/v2.php/apps/spreed/api/v1/bot/${normalizedToken}/reaction/${messageId}`;
205	
206	  const { response, release } = await fetchWithSsrFGuard({
207	    url,
208	    init: {
209	      method: "POST",
210	      headers: {
211	        "Content-Type": "application/json",
212	        "OCS-APIRequest": "true",
213	        "X-Nextcloud-Talk-Bot-Random": random,
214	        "X-Nextcloud-Talk-Bot-Signature": signature,
215	      },
216	      body,
217	    },
218	    auditContext: "nextcloud-talk-reaction",
219	    policy: account.config?.allowPrivateNetwork ? { allowPrivateNetwork: true } : undefined,
220	  });
221	
222	  try {
223	    if (!response.ok) {
224	      const errorBody = await response.text().catch(() => "");
225	      throw new Error(`Nextcloud Talk reaction failed: ${response.status} ${errorBody}`.trim());
226	    }
227	
228	    return { ok: true };
229	  } finally {
230	    await release();
231	  }
232	}
