186	export function readNextcloudTalkWebhookBody(
187	  req: IncomingMessage,
188	  maxBodyBytes: number,
189	): Promise<string> {
190	  return readRequestBodyWithLimit(req, {
191	    // This read happens before signature verification, so keep the unauthenticated
192	    // body budget bounded even if the operator-configured post-parse limit is larger.
193	    maxBytes: Math.min(maxBodyBytes, PREAUTH_WEBHOOK_MAX_BODY_BYTES),
194	    timeoutMs: PREAUTH_WEBHOOK_BODY_TIMEOUT_MS,
195	  });
