198	export function createNextcloudTalkWebhookServer(opts: NextcloudTalkWebhookServerOptions): {
199	  server: Server;
200	  start: () => Promise<void>;
201	  stop: () => void;
202	} {
203	  const { port, host, path, secret, onMessage, onError, abortSignal } = opts;
204	  const maxBodyBytes =
205	    typeof opts.maxBodyBytes === "number" &&
206	    Number.isFinite(opts.maxBodyBytes) &&
207	    opts.maxBodyBytes > 0
208	      ? Math.floor(opts.maxBodyBytes)
209	      : DEFAULT_WEBHOOK_MAX_BODY_BYTES;
210	  const readBody = opts.readBody ?? readNextcloudTalkWebhookBody;
211	  const isBackendAllowed = opts.isBackendAllowed;
212	  const shouldProcessMessage = opts.shouldProcessMessage;
213	  const webhookAuthRateLimiter = createAuthRateLimiter({
214	    maxAttempts: WEBHOOK_RATE_LIMIT_DEFAULTS.maxRequests,
215	    windowMs: WEBHOOK_RATE_LIMIT_DEFAULTS.windowMs,
216	    lockoutMs: WEBHOOK_RATE_LIMIT_DEFAULTS.windowMs,
217	    exemptLoopback: false,
218	    pruneIntervalMs: WEBHOOK_RATE_LIMIT_DEFAULTS.windowMs,
219	  });
220	
221	  const server = createServer(async (req: IncomingMessage, res: ServerResponse) => {
222	    if (req.url === HEALTH_PATH) {
223	      res.writeHead(200, { "Content-Type": "text/plain" });
224	      res.end("ok");
225	      return;
226	    }
227	
228	    if (req.url !== path || req.method !== "POST") {
229	      res.writeHead(404);
230	      res.end();
231	      return;
232	    }
233	
234	    const clientIp = req.socket.remoteAddress ?? "unknown";
235	    if (!webhookAuthRateLimiter.check(clientIp, WEBHOOK_AUTH_RATE_LIMIT_SCOPE).allowed) {
236	      res.writeHead(429);
237	      res.end("Too Many Requests");
238	      return;
239	    }
240	
241	    try {
242	      const headers = validateWebhookHeaders({
243	        req,
244	        res,
245	        isBackendAllowed,
246	      });
247	      if (!headers) {
248	        return;
249	      }
250	
251	      const body = await readBody(req, maxBodyBytes);
252	
253	      const hasValidSignature = verifyWebhookSignature({
254	        headers,
255	        body,
256	        secret,
257	        res,
258	        clientIp,
259	        authRateLimiter: webhookAuthRateLimiter,
260	      });
261	      if (!hasValidSignature) {
262	        return;
263	      }
264	
265	      const decoded = decodeWebhookCreateMessage({
266	        body,
267	        res,
268	      });
269	      if (decoded.kind === "invalid") {
270	        return;
271	      }
272	      if (decoded.kind === "ignore") {
273	        writeJsonResponse(res, 200);
274	        return;
275	      }
276	
277	      const message = decoded.message;
278	      if (shouldProcessMessage) {
279	        const shouldProcess = await shouldProcessMessage(message);
280	        if (!shouldProcess) {
281	          writeJsonResponse(res, 200);
282	          return;
283	        }
284	      }
285	
286	      writeJsonResponse(res, 200);
287	
288	      try {
289	        await onMessage(message);
290	      } catch (err) {
291	        onError?.(err instanceof Error ? err : new Error(formatError(err)));
292	      }
293	    } catch (err) {
294	      if (isRequestBodyLimitError(err, "PAYLOAD_TOO_LARGE")) {
295	        writeWebhookError(res, 413, WEBHOOK_ERRORS.payloadTooLarge);
296	        return;
297	      }
298	      if (isRequestBodyLimitError(err, "REQUEST_BODY_TIMEOUT")) {
299	        writeWebhookError(res, 408, requestBodyErrorToText("REQUEST_BODY_TIMEOUT"));
300	        return;
301	      }
302	      const error = err instanceof Error ? err : new Error(formatError(err));
303	      onError?.(error);
304	      writeWebhookError(res, 500, WEBHOOK_ERRORS.internalServerError);
305	    }
306	  });
307	
308	  const start = (): Promise<void> => {
309	    return new Promise((resolve) => {
310	      server.listen(port, host, () => resolve());
311	    });
312	  };
313	
314	  let stopped = false;
315	  const stop = () => {
316	    if (stopped) {
317	      return;
318	    }
319	    stopped = true;
320	    try {
321	      server.close();
322	    } catch {
323	      // ignore close races while shutting down
324	    }
325	  };
326	
327	  if (abortSignal) {
328	    if (abortSignal.aborted) {
329	      stop();
330	    } else {
331	      abortSignal.addEventListener("abort", stop, { once: true });
332	    }
333	  }
334	
335	  return { server, start, stop };
336	}
