338	export type NextcloudTalkMonitorOptions = {
339	  accountId?: string;
340	  config?: CoreConfig;
341	  runtime?: RuntimeEnv;
342	  abortSignal?: AbortSignal;
343	  onMessage?: (message: NextcloudTalkInboundMessage) => void | Promise<void>;
344	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
345	};
