347	export async function monitorNextcloudTalkProvider(
348	  opts: NextcloudTalkMonitorOptions,
349	): Promise<{ stop: () => void }> {
350	  const core = getNextcloudTalkRuntime();
351	  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
352	  const account = resolveNextcloudTalkAccount({
353	    cfg,
354	    accountId: opts.accountId,
355	  });
356	  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
357	    opts.runtime,
358	    core.logging.getChildLogger(),
359	  );
360	
361	  if (!account.secret) {
362	    throw new Error(`Nextcloud Talk bot secret not configured for account "${account.accountId}"`);
363	  }
364	
365	  const port = account.config.webhookPort ?? DEFAULT_WEBHOOK_PORT;
366	  const host = account.config.webhookHost ?? DEFAULT_WEBHOOK_HOST;
367	  const path = account.config.webhookPath ?? DEFAULT_WEBHOOK_PATH;
368	
369	  const logger = core.logging.getChildLogger({
370	    channel: "nextcloud-talk",
371	    accountId: account.accountId,
372	  });
373	  const expectedBackendOrigin = normalizeOrigin(account.baseUrl);
374	  const replayGuard = createNextcloudTalkReplayGuard({
375	    stateDir: core.state.resolveStateDir(process.env, os.homedir),
376	    onDiskError: (error) => {
377	      logger.warn(
378	        `[nextcloud-talk:${account.accountId}] replay guard disk error: ${String(error)}`,
379	      );
380	    },
381	  });
382	
383	  const { start, stop } = createNextcloudTalkWebhookServer({
384	    port,
385	    host,
386	    path,
387	    secret: account.secret,
388	    isBackendAllowed: (backend) => {
389	      if (!expectedBackendOrigin) {
390	        return true;
391	      }
392	      const backendOrigin = normalizeOrigin(backend);
393	      return backendOrigin === expectedBackendOrigin;
394	    },
395	    shouldProcessMessage: async (message) => {
396	      const shouldProcess = await replayGuard.shouldProcessMessage({
397	        accountId: account.accountId,
398	        roomToken: message.roomToken,
399	        messageId: message.messageId,
400	      });
401	      if (!shouldProcess) {
402	        logger.warn(
403	          `[nextcloud-talk:${account.accountId}] replayed webhook ignored room=${message.roomToken} messageId=${message.messageId}`,
404	        );
405	      }
406	      return shouldProcess;
407	    },
408	    onMessage: async (message) => {
409	      core.channel.activity.record({
410	        channel: "nextcloud-talk",
411	        accountId: account.accountId,
412	        direction: "inbound",
413	        at: message.timestamp,
414	      });
415	      if (opts.onMessage) {
416	        await opts.onMessage(message);
417	        return;
418	      }
419	      await handleNextcloudTalkInbound({
420	        message,
421	        account,
422	        config: cfg,
423	        runtime,
424	        statusSink: opts.statusSink,
425	      });
426	    },
427	    onError: (error) => {
428	      logger.error(`[nextcloud-talk:${account.accountId}] webhook error: ${error.message}`);
429	    },
430	    abortSignal: opts.abortSignal,
431	  });
432	
433	  if (opts.abortSignal?.aborted) {
434	    return { stop };
435	  }
436	  await start();
437	  if (opts.abortSignal?.aborted) {
438	    stop();
439	    return { stop };
440	  }
441	
442	  const publicUrl =
443	    account.config.webhookPublicUrl ??
444	    `http://${host === "0.0.0.0" ? "localhost" : host}:${port}${path}`;
445	  logger.info(`[nextcloud-talk:${account.accountId}] webhook listening on ${publicUrl}`);
446	
447	  return { stop };
448	}
