37	export function validateNextcloudTalkBaseUrl(value: string): string | undefined {
38	  if (!value) {
39	    return "Required";
40	  }
41	  if (!value.startsWith("http://") && !value.startsWith("https://")) {
42	    return "URL must start with http:// or https://";
