47	export function setNextcloudTalkAccountConfig(
48	  cfg: CoreConfig,
49	  accountId: string,
50	  updates: Record<string, unknown>,
51	): CoreConfig {
52	  return patchScopedAccountConfig({
53	    cfg,
54	    channelKey: channel,
