60	export function clearNextcloudTalkAccountFields(
61	  cfg: CoreConfig,
62	  accountId: string,
63	  fields: string[],
64	): CoreConfig {
65	  const section = cfg.channels?.["nextcloud-talk"];
66	  if (!section) {
67	    return cfg;
68	  }
69	
70	  if (accountId === DEFAULT_ACCOUNT_ID) {
