```

> **Note:** `buildWebhookChannelStatusSummary` may need to be verified at implementation time against the actual `status-helpers` subpath exports. Fall back to `buildBaseChannelStatusSummary` with extra fields if unavailable.

---

### Step 7 — `src/types.ts`

Defines all TypeScript types for PulseBoard configs, webhook payloads, and inbound/outbound messages. Pattern follows `extensions/nextcloud-talk/src/types.ts`:

```typescript
import type { BlockStreamingCoalesceConfig, DmConfig, DmPolicy, GroupPolicy } from "../runtime-api.js";

export type { DmPolicy, GroupPolicy };

export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: { allow?: string[]; deny?: string[] };
  skills?: string[];
  enabled?: boolean;
  allowFrom?: string[];
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** Base URL of the PulseBoard server (e.g. "https://pb.example.com"). */
  baseUrl?: string;
  /** API token for outbound HTTP calls. */
  apiToken?: string;
  /** Shared secret for verifying inbound webhook HMAC-SHA256 signatures. */
  webhookSecret?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: string[];
  groupAllowFrom?: string[];
  groupPolicy?: GroupPolicy;
  /** Per-board configuration (key is board slug). */
  boards?: Record<string, PulseBoardBoardConfig>;
  webhookPort?: number;
  webhookHost?: string;
  webhookPath?: string;
  webhookPublicUrl?: string;
  historyLimit?: number;
  dmHistoryLimit?: number;
  dms?: Record<string, DmConfig>;
  textChunkLimit?: number;
  chunkMode?: "length" | "newline";
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  responsePrefix?: string;
  mediaMaxMb?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = {
  channels?: { pulseboard?: PulseBoardConfig };
  [key: string]: unknown;
};

/** Inbound webhook payload sent by the PulseBoard server. */
export type PulseBoardWebhookPayload = {
  messageId: string;
  chatType: "board" | "direct";
  boardName?: string | null;
  senderId: string;
  senderName: string;
  text: string;
  timestamp: number;
};

/** Normalized inbound message after parsing the webhook payload. */
export type PulseBoardInboundMessage = {
  messageId: string;
  isGroup: boolean;
  /** Board slug for groups; sender user ID for DMs. */
  target: string;
  senderId: string;
  senderName: string;
  text: string;
  timestamp: number;
};

/** Result of sending a message via the PulseBoard API. */
export type PulseBoardSendResult = {
  messageId: string;
  target: string;
};
```

---

### Step 8 — `src/config-schema.ts`

Zod validation schema following the pattern of `extensions/nextcloud-talk/src/config-schema.ts`. Key difference: PulseBoard uses simple `z.string()` for `apiToken` and `webhookSecret` (no `buildSecretInputSchema` needed for a simpler credential shape).

```typescript
import {
  BlockStreamingCoalesceSchema,
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
  ReplyRuntimeConfigSchemaShape,
  ToolPolicySchema,
  requireOpenAllowFrom,
} from "openclaw/plugin-sdk/channel-config-schema";
import { requireChannelOpenAllowFrom } from "openclaw/plugin-sdk/extension-shared";
import { z } from "openclaw/plugin-sdk/zod";

export const PulseBoardBoardSchema = z
  .object({
    requireMention: z.boolean().optional(),
    tools: ToolPolicySchema,
    skills: z.array(z.string()).optional(),
    enabled: z.boolean().optional(),
    allowFrom: z.array(z.string()).optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

export const PulseBoardAccountSchemaBase = z
  .object({
    name: z.string().optional(),
    enabled: z.boolean().optional(),
    baseUrl: z.string().optional(),
    apiToken: z.string().optional(),
    webhookSecret: z.string().optional(),
    dmPolicy: DmPolicySchema.optional().default("pairing"),
    allowFrom: z.array(z.string()).optional(),
    groupAllowFrom: z.array(z.string()).optional(),
    groupPolicy: GroupPolicySchema.optional().default("allowlist"),
    boards: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),
    webhookPort: z.number().int().positive().optional(),
    webhookHost: z.string().optional(),
    webhookPath: z.string().optional(),
    webhookPublicUrl: z.string().optional(),
    markdown: MarkdownConfigSchema,
    ...ReplyRuntimeConfigSchemaShape,
  })
  .strict();

export const PulseBoardAccountSchema = PulseBoardAccountSchemaBase.superRefine((value, ctx) => {
  requireChannelOpenAllowFrom({
    channel: "pulseboard",
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    requireOpenAllowFrom,
  });
});

export const PulseBoardConfigSchema = PulseBoardAccountSchemaBase.extend({
  accounts: z.record(z.string(), PulseBoardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((value, ctx) => {
  requireChannelOpenAllowFrom({
    channel: "pulseboard",
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    requireOpenAllowFrom,
  });
});
```

---

### Step 9 — `src/accounts.ts`

Account resolution following `extensions/nextcloud-talk/src/accounts.ts`. Key functions:
- `resolveDefaultPulseBoardAccountId(cfg)` — delegates to `createAccountListHelpers`
- `listPulseBoardAccountIds(cfg)` — delegates to `createAccountListHelpers`
- `resolvePulseBoardAccount({ cfg, accountId })` — merges config layers, reads `PULSEBOARD_API_TOKEN` env var and `PULSEBOARD_WEBHOOK_SECRET` env var for the default account, returns a `ResolvedPulseBoardAccount`

```typescript
export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  baseUrl: string;
  apiToken: string;
  apiTokenSource: "env" | "config" | "none";
  webhookSecret: string;
  webhookSecretSource: "env" | "config" | "none";
  config: PulseBoardAccountConfig;
};
```

The `configured` property (used by `channel.ts`) is `Boolean(account.apiToken && account.webhookSecret && account.baseUrl)`.

---

### Step 10 — `src/normalize.ts`

Target normalization utilities:

```typescript
// Strip pulseboard:/pulse-board:/pb: prefixes, then return normalized form
export function stripPulseBoardTargetPrefix(raw: string): string | undefined { ... }

// Return canonical "pulseboard:<slug>" (board) or "pulseboard:@<userId>" (DM)
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined { ... }

// Return true if the raw string looks like a PulseBoard target id
export function looksLikePulseBoardTargetId(raw: string): boolean { ... }

// True if the normalized target is a board (group)
export function isBoardTarget(normalized: string): boolean {
  const bare = stripPulseBoardTargetPrefix(normalized) ?? "";
  return !bare.startsWith("@");
}
```

Key rules:
- `@` prefix → DM, no `@` prefix → board
- `pulseboard:general` → board `general`
- `pulseboard:@alice` → DM to user `alice`
- Strip known aliases `pulse-board:`, `pb:` before normalizing

---

### Step 11 — `src/policy.ts`

Board-level group policy helpers:

```typescript
export function resolvePulseBoardBoardMatch(params: {
  boards?: Record<string, PulseBoardBoardConfig>;
  boardName: string;
}): { boardConfig?: PulseBoardBoardConfig; wildcardConfig?: PulseBoardBoardConfig; allowed: boolean };

export function resolvePulseBoardRequireMention(params: {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
}): boolean;  // defaults true

export function resolvePulseBoardGroupToolPolicy(params: {
  cfg: CoreConfig; accountId?: string | null; groupId?: string | null;
}): { allow?: string[]; deny?: string[] } | undefined;
```

Mirrors `extensions/nextcloud-talk/src/policy.ts` structures.

---

### Step 12 — `src/runtime.ts`

Plugin runtime store (identical pattern to all other plugins):

```typescript
import { createPluginRuntimeStore } from "openclaw/plugin-sdk/runtime-store";
import type { PluginRuntime } from "openclaw/plugin-sdk/core";

const { setRuntime: setPulseBoardRuntime, getRuntime: getPulseBoardRuntime } =
  createPluginRuntimeStore<PluginRuntime>("PulseBoard runtime not initialized");

export { getPulseBoardRuntime, setPulseBoardRuntime };
```

---

### Step 13 — `src/send.ts`

Outbound HTTP message sending via the PulseBoard REST API:

```typescript
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: { cfg?: CoreConfig; accountId?: string; replyTo?: string } = {},
): Promise<PulseBoardSendResult>
```

Implementation:
1. Resolve account from `getPulseBoardRuntime().config.loadConfig()` (or `opts.cfg`)
2. Strip `pulseboard:` prefix from `to`; detect DM (`@`) vs board
3. Apply markdown table conversion (`resolveMarkdownTableMode` + `convertMarkdownTables`)
4. `POST` to `<baseUrl>/api/v1/boards/<board>/messages` or `.../dms/<userId>/messages`
5. Include `Authorization: Bearer <apiToken>` header
6. Record outbound activity: `getPulseBoardRuntime().channel.activity.record({ channel: "pulseboard", ... })`
7. Return `{ messageId, target }`

Error handling: specific messages for 401 (invalid token), 404 (board/user not found), 403 (forbidden).

---

### Step 14 — `src/monitor.ts`

Webhook HTTP server plus the `monitorPulseBoardProvider()` orchestration function. Modelled closely on `extensions/nextcloud-talk/src/monitor.ts`.

Key functions:

```typescript
export function createPulseBoardWebhookServer(opts: {
  port: number;
  host: string;
  path: string;
  webhookSecret: string;
  onMessage: (message: PulseBoardInboundMessage) => void | Promise<void>;
  onError?: (error: Error) => void;
  abortSignal?: AbortSignal;
}): { server: Server; start: () => Promise<void>; stop: () => void }
```

Signature verification in `createPulseBoardWebhookServer`:
1. Read `X-PulseBoard-Signature` request header
2. Compute `HMAC-SHA256(webhookSecret, rawBody)` using `node:crypto`
3. Compare using timing-safe equality
4. Parse payload with Zod schema (`PulseBoardWebhookPayloadSchema`)
5. Map to `PulseBoardInboundMessage`

```typescript
export async function monitorPulseBoardProvider(opts: {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
}): Promise<{ stop: () => void }>
```

`monitorPulseBoardProvider` follows the Nextcloud Talk monitor pattern:
1. Resolve account
2. Get logger from `core.logging.getChildLogger`
3. Create webhook server with the account's secret/port/path
4. On message: call `core.channel.activity.record` then `handlePulseBoardInbound()`
5. `await start()`, log public URL
6. Return `{ stop }`

---

### Step 15 — `src/inbound.ts`

The core inbound dispatch handler. Closely mirrors `extensions/nextcloud-talk/src/inbound.ts`. Because there is no `dispatchInboundReplyWithBase` available from a public SDK subpath, this file builds the dispatch pipeline directly using the `PluginRuntime` (`core`) API:

```typescript
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void>
```

Pipeline (step by step, using `core = getPulseBoardRuntime()`):

1. **Guard**: skip empty text
2. **Status**: `statusSink?.({ lastInboundAt: message.timestamp })`
3. **Policy**: resolve `dmPolicy`, `groupPolicy` via `resolveAllowlistProviderRuntimeGroupPolicy` / `resolveDefaultGroupPolicy`
4. **Group allowlist**: for board messages, check `resolvePulseBoardBoardMatch` — drop if board not in allowlist
5. **DM/group access**: `resolveDmGroupAccessWithCommandGate` against config + store allowlists; handle pairing challenge for DMs using `createChannelPairingController`
6. **Mention gate**: for group messages, resolve `requireMention` from board config; use `core.channel.mentions.buildMentionRegexes` + `matchesMentionPatterns`
7. **Route**: `core.channel.routing.resolveAgentRoute({ cfg, channel: "pulseboard", accountId, peer: { kind: isGroup ? "group" : "direct", id: target } })`
8. **Envelope**: `core.channel.session.resolveStorePath(...)` + `core.channel.reply.formatAgentEnvelope({ channel: "PulseBoard", from: fromLabel, timestamp, body: rawBody })`
9. **Context**: `core.channel.reply.finalizeInboundContext({ Body, From, To, SessionKey, AccountId, ChatType, ... })`
10. **Dispatch**: `core.channel.session.recordInboundSession(...)` then `core.channel.reply.dispatchReplyWithBufferedBlockDispatcher(...)` — these are the same two steps that `dispatchInboundReplyWithBase` wraps internally

**Deliver** helper used in step 10:
```typescript
async function deliverPulseBoardReply(params: {
  payload: OutboundReplyPayload;
  target: string;
  accountId: string;
  statusSink?: (patch: { lastOutboundAt?: number }) => void;
}): Promise<void> {
  await deliverFormattedTextWithAttachments({
    payload: params.payload,
    send: async ({ text, replyToId }) => {
      await sendMessagePulseBoard(params.target, text, {
        accountId: params.accountId,
        replyTo: replyToId,
      });
      params.statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}
```

---

### Step 16 — `src/channel.ts`

The main plugin definition using `createChatChannelPlugin`. Mirrors `extensions/nextcloud-talk/src/channel.ts` closely.

**Key wiring:**

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard (Boards + DMs)",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Real-time bulletin board with named boards and direct messages.",
        aliases: ["pulse-board", "pb"],
        order: 70,
        quickstartAllowFrom: true,
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        reactions: false,
        threads: false,
        media: true,
        nativeCommands: false,
        blockStreaming: true,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
      config: {
        ...pulseBoardConfigAdapter,         // createScopedChannelConfigAdapter
        isConfigured: (account) =>
          Boolean(account.apiToken && account.webhookSecret && account.baseUrl),
        describeAccount: (account) =>
          describeWebhookAccountSnapshot({
            account,
            configured: Boolean(account.apiToken && account.webhookSecret && account.baseUrl),
            extra: {
              apiTokenSource: account.apiTokenSource,
              webhookSecretSource: account.webhookSecretSource,
              baseUrl: account.baseUrl ? "[set]" : "[missing]",
            },
          }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => { ... },
        resolveToolPolicy: resolvePulseBoardGroupToolPolicy,
      },
      messaging: {
        normalizeTarget: normalizePulseBoardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseBoardTargetId,
          hint: "<boardName | @userId>",
        },
      },
      setup: pulseBoardSetupAdapter,
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ snapshot }) =>
          buildBaseChannelStatusSummary(snapshot, {
            mode: "webhook",
          }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: Boolean(account.apiToken && account.webhookSecret && account.baseUrl),
          extra: {
            apiTokenSource: account.apiTokenSource,
            webhookSecretSource: account.webhookSecretSource,
            baseUrl: account.baseUrl ? "[set]" : "[missing]",
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          if (!ctx.account.apiToken || !ctx.account.webhookSecret || !ctx.account.baseUrl) {
            throw new Error(
              `PulseBoard not configured for "${ctx.account.accountId}" (missing apiToken, webhookSecret, or baseUrl)`,
            );
          }
          ctx.log?.info(`[${ctx.account.accountId}] starting PulseBoard webhook server`);
          const statusSink = createAccountStatusSink({ accountId: ctx.accountId, setStatus: ctx.setStatus });
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              await monitorPulseBoardProvider({
                accountId: ctx.account.accountId,
                config: ctx.cfg as CoreConfig,
                runtime: ctx.runtime,
                abortSignal: ctx.abortSignal,
                statusSink,
              }),
          });
        },
        logoutAccount: async ({ accountId, cfg }) => { /* clear apiToken + webhookSecret */ },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUserId",
        message: "OpenClaw: your access has been approved.",
        normalizeAllowEntry: createPairingPrefixStripper(
          /^(pulseboard|pulse-board|pb):/i,
          (entry) => entry.replace(/^@/, "").toLowerCase(),
        ),
        notify: createLoggedPairingApprovalNotifier(
          ({ id }) => `[pulseboard] User ${id} approved for pairing`,
        ),
      },
    },
    security: {
      resolveDmPolicy: createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
        channelKey: "pulseboard",
        resolvePolicy: (account) => account.config.dmPolicy,
        resolveAllowFrom: (account) => account.config.allowFrom,
        policyPathSuffix: "dmPolicy",
        normalizeEntry: (raw) =>
          raw.trim().replace(/^(pulseboard|pulse-board|pb):/i, "").replace(/^@/, "").toLowerCase(),
      }),
      collectWarnings: createAllowlistProviderRouteAllowlistWarningCollector<ResolvedPulseBoardAccount>({
        providerConfigPresent: (cfg) =>
          (cfg.channels as Record<string, unknown> | undefined)?.["pulseboard"] !== undefined,
        resolveGroupPolicy: (account) => account.config.groupPolicy,
        resolveRouteAllowlistConfigured: (account) =>
          Boolean(account.config.boards) && Object.keys(account.config.boards ?? {}).length > 0,
        restrictSenders: {
          surface: "PulseBoard boards",
          openScope: "any member in allowed boards",
          groupPolicyPath: "channels.pulseboard.groupPolicy",
          groupAllowFromPath: "channels.pulseboard.groupAllowFrom",
        },
        noRouteAllowlist: {
          surface: "PulseBoard boards",
          routeAllowlistPath: "channels.pulseboard.boards",
          routeScope: "board",
          groupPolicyPath: "channels.pulseboard.groupPolicy",
          groupAllowFromPath: "channels.pulseboard.groupAllowFrom",
        },
      }),
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: (text, limit) =>
          getPulseBoardRuntime().channel.text.chunkMarkdownText(text, limit),
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, text, {
            accountId: accountId ?? undefined,
            replyTo: replyToId ?? undefined,
            cfg: cfg as CoreConfig,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
            accountId: accountId ?? undefined,
            replyTo: replyToId ?? undefined,
            cfg: cfg as CoreConfig,
          }),
      },
    },
  });
```

---

### Step 17 — `src/setup-core.ts`

`ChannelSetupAdapter` implementation following `extensions/nextcloud-talk/src/setup-core.ts`.

Key exported items:
- `pulseBoardSetupAdapter: ChannelSetupAdapter` — `resolveAccountId`, `applyAccountName`, `validateInput`, `applyAccountConfig`
- `setPulseBoardAccountConfig(cfg, accountId, updates)` — wraps `patchScopedAccountConfig`
- `pulseBoardDmPolicy: ChannelSetupDmPolicy` — `createTopLevelChannelDmPolicy(...)` for `channels.pulseboard.dmPolicy`

`validateInput` requires: `baseUrl`, and either `apiToken`/`webhookSecret` or `--use-env` with `PULSEBOARD_API_TOKEN` + `PULSEBOARD_WEBHOOK_SECRET` env vars set.

---

### Step 18 — `src/setup-surface.ts`

`ChannelSetupWizard` implementation following `extensions/nextcloud-talk/src/setup-surface.ts` and `extensions/irc/src/setup-surface.ts`.

Wizard steps:
1. **introNote**: shown when not yet configured; lists env vars: `PULSEBOARD_API_TOKEN`, `PULSEBOARD_WEBHOOK_SECRET`, `PULSEBOARD_BASE_URL`
2. **prepare**: check for `PULSEBOARD_BASE_URL` + `PULSEBOARD_API_TOKEN` + `PULSEBOARD_WEBHOOK_SECRET` env vars and offer `--use-env` shortcut
