207	  cfg: OpenClawConfig;
208	  agentId: string;
209	  channel: string;
210	  accountId?: string | null;
211	  peer: { kind: "direct" | "group" | "channel"; id: string };
212	  chatType: "direct" | "group" | "channel";
213	  from: string;
214	  to: string;
215	  threadId?: string | number;
216	}): ChannelOutboundSessionRoute {
217	  const baseSessionKey = buildOutboundBaseSessionKey({
218	    cfg: params.cfg,
219	    agentId: params.agentId,
220	    channel: params.channel,
221	    accountId: params.accountId,
222	    peer: params.peer,
223	  });
224	  return {
225	    sessionKey: baseSessionKey,
226	    baseSessionKey,
227	    peer: params.peer,
228	    chatType: params.chatType,
229	    from: params.from,
230	    to: params.to,
