import {
  DEFAULT_ACCOUNT_ID,
  createAccountListHelpers,
  normalizeAccountId,
  resolveMergedAccountConfig,
  resolveAccountWithDefaultFallback,
} from "../runtime-api.js";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  baseUrl: string;
  apiToken: string;
  apiTokenSource: "env" | "config" | "none";
  webhookSecret: string;
  webhookSecretSource: "env" | "config" | "none";
  config: PulseBoardAccountConfig;
};

const {
  listAccountIds: listPulseBoardAccountIdsInternal,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", {
  normalizeAccountId,
});
export { resolveDefaultPulseBoardAccountId };

export function listPulseBoardAccountIds(cfg: CoreConfig): string[] {
  return listPulseBoardAccountIdsInternal(cfg);
}

function mergePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as
      | Record<string, Partial<PulseBoardAccountConfig>>
      | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}

function resolvePulseBoardApiToken(
  cfg: CoreConfig,
  accountId: string,
): { apiToken: string; source: ResolvedPulseBoardAccount["apiTokenSource"] } {
  const merged = mergePulseBoardAccountConfig(cfg, accountId);

  // Env var only applies to the default account
  const envToken = process.env.PULSEBOARD_API_TOKEN?.trim();
  if (envToken && accountId === DEFAULT_ACCOUNT_ID) {
    return { apiToken: envToken, source: "env" };
  }

  const inlineToken = merged.apiToken?.trim();
  if (inlineToken) {
    return { apiToken: inlineToken, source: "config" };
  }

  return { apiToken: "", source: "none" };
}

function resolvePulseBoardWebhookSecret(
  cfg: CoreConfig,
  accountId: string,
): { webhookSecret: string; source: ResolvedPulseBoardAccount["webhookSecretSource"] } {
  const merged = mergePulseBoardAccountConfig(cfg, accountId);

  // Env var only applies to the default account
  const envSecret = process.env.PULSEBOARD_WEBHOOK_SECRET?.trim();
  if (envSecret && accountId === DEFAULT_ACCOUNT_ID) {
    return { webhookSecret: envSecret, source: "env" };
  }

  const inlineSecret = merged.webhookSecret?.trim();
  if (inlineSecret) {
    return { webhookSecret: inlineSecret, source: "config" };
  }

  return { webhookSecret: "", source: "none" };
}

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const baseEnabled = params.cfg.channels?.pulseboard?.enabled !== false;

  const resolve = (accountId: string): ResolvedPulseBoardAccount => {
    const merged = mergePulseBoardAccountConfig(params.cfg, accountId);
    const accountEnabled = merged.enabled !== false;
    const enabled = baseEnabled && accountEnabled;
    const tokenResolution = resolvePulseBoardApiToken(params.cfg, accountId);
    const secretResolution = resolvePulseBoardWebhookSecret(params.cfg, accountId);
    const baseUrl = merged.baseUrl?.trim()?.replace(/\/$/, "") ?? "";

    return {
      accountId,
      enabled,
      name: merged.name?.trim() || undefined,
      baseUrl,
      apiToken: tokenResolution.apiToken,
      apiTokenSource: tokenResolution.source,
      webhookSecret: secretResolution.webhookSecret,
      webhookSecretSource: secretResolution.source,
      config: merged,
    };
  };

  return resolveAccountWithDefaultFallback({
    accountId: params.accountId,
    normalizeAccountId,
    resolvePrimary: resolve,
    hasCredential: (account) =>
      account.apiTokenSource !== "none" && account.webhookSecretSource !== "none",
    resolveDefaultAccountId: () => resolveDefaultPulseBoardAccountId(params.cfg),
  });
}

export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

