/** Known channel-prefix aliases for PulseBoard targets. */
const PREFIX_RE = /^(pulseboard|pulse-board|pb):/i;

/**
 * Strip any recognized PulseBoard channel prefix from a raw target string.
 * Returns the bare slug/id, or undefined if input is empty.
 */
export function stripPulseBoardTargetPrefix(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  return trimmed.replace(PREFIX_RE, "").trim() || undefined;
}

/**
 * Return the canonical "pulseboard:<slug>" (board) or "pulseboard:@<userId>" (DM)
 * form for a raw target string, or undefined if the input cannot be normalized.
 *
 * Rules:
 * - Strings starting with `@` (after prefix strip) → DM
 * - All other non-empty strings → board (group)
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const bare = stripPulseBoardTargetPrefix(raw);
  if (!bare) {
    return undefined;
  }
  return `pulseboard:${bare}`;
}

/**
 * Return true when the raw string looks like a PulseBoard target id
 * (with or without a recognized prefix).
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Explicit prefix → definitely a PulseBoard target
  if (PREFIX_RE.test(trimmed)) {
    return true;
  }
  // Plain board slug (lowercase alphanumeric + hyphens) or DM (@userId)
  return /^@?[a-z0-9]([a-z0-9_-]*[a-z0-9])?$/i.test(trimmed);
}

/**
 * Return true when the normalized target represents a board (group), i.e. it
 * does NOT have an `@` prefix on the bare portion.
 */
export function isBoardTarget(normalized: string): boolean {
  const bare = stripPulseBoardTargetPrefix(normalized) ?? "";
  return Boolean(bare) && !bare.startsWith("@");
}

