import {
  convertMarkdownTables,
  resolveMarkdownTableMode,
} from "../runtime-api.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { stripPulseBoardTargetPrefix } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardSendResult } from "./types.js";

/**
 * Send a text message to a PulseBoard board or DM via the REST API.
 * `to` may be a normalized target like `pulseboard:general` or `pulseboard:@alice`.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: {
    cfg?: CoreConfig;
    accountId?: string;
    replyTo?: string;
  } = {},
): Promise<PulseBoardSendResult> {
  const core = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? core.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.apiToken || !account.baseUrl) {
    throw new Error(
      `PulseBoard not configured for account "${account.accountId}" (missing apiToken or baseUrl)`,
    );
  }

  if (!text?.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  // Resolve the bare target (strip pulseboard: prefix)
  const bareTarget = stripPulseBoardTargetPrefix(to) ?? to.trim();
  const isDm = bareTarget.startsWith("@");

  // Apply markdown table conversion if configured
  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const message = convertMarkdownTables(text.trim(), tableMode);

  // Determine the API endpoint
  let url: string;
  if (isDm) {
    const userId = bareTarget.slice(1); // strip @
    url = `${account.baseUrl}/api/v1/dms/${encodeURIComponent(userId)}/messages`;
  } else {
    url = `${account.baseUrl}/api/v1/boards/${encodeURIComponent(bareTarget)}/messages`;
  }

  const bodyPayload: Record<string, unknown> = { text: message };
  if (opts.replyTo) {
    bodyPayload.replyTo = opts.replyTo;
  }

  const response = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.apiToken}`,
    },
    body: JSON.stringify(bodyPayload),
  });

  if (!response.ok) {
    const status = response.status;
    if (status === 401) {
      throw new Error(`PulseBoard authentication failed (invalid API token) for "${to}"`);
    }
    if (status === 403) {
      throw new Error(`PulseBoard access forbidden for "${to}"`);
    }
    if (status === 404) {
      throw new Error(
        `PulseBoard target not found: "${to}" (board or user does not exist)`,
      );
    }
    throw new Error(`PulseBoard send failed: HTTP ${status} for "${to}"`);
  }

  let messageId = "";
  try {
    const data = (await response.json()) as { messageId?: string };
    messageId = data?.messageId ?? "";
  } catch {
    // Response parsing failed, but message was sent.
  }

  // Record outbound activity on the runtime
  try {
    core.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "outbound",
    });
  } catch (err) {
    if (!(err instanceof Error) || err.message !== "PulseBoard runtime not initialized") {
      throw err;
    }
  }

  return { messageId, target: to };
}

