import {
  GROUP_POLICY_BLOCKED_LABEL,
  createChannelPairingController,
  createChannelReplyPipeline,
  createNormalizedOutboundDeliverer,
  deliverFormattedTextWithAttachments,
  dispatchReplyWithBufferedBlockDispatcher,
  logInboundDrop,
  readStoreAllowFromForDmPolicy,
  resolveDmGroupAccessWithCommandGate,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  warnMissingProviderGroupPolicyFallbackOnce,
} from "../runtime-api.js";
import type { OpenClawConfig, OutboundReplyPayload, RuntimeEnv } from "../runtime-api.js";
import type { ResolvedPulseBoardAccount } from "./accounts.js";
import {
  isPulseBoardSenderAllowed,
  normalizePulseBoardAllowlist,
  resolvePulseBoardBoardMatch,
  resolvePulseBoardRequireMention,
} from "./policy.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, GroupPolicy, PulseBoardInboundMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

async function deliverPulseBoardReply(params: {
  payload: OutboundReplyPayload;
  target: string;
  accountId: string;
  statusSink?: (patch: { lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { payload, target, accountId, statusSink } = params;
  await deliverFormattedTextWithAttachments({
    payload,
    send: async ({ text, replyToId }) => {
      await sendMessagePulseBoard(target, text, {
        accountId,
        replyTo: replyToId,
      });
      statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}

export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime, statusSink } = params;
  const core = getPulseBoardRuntime();
  const pairing = createChannelPairingController({
    core,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  const { isGroup, target, senderId, senderName } = message;

  statusSink?.({ lastInboundAt: message.timestamp });

  // Resolve group / DM policies
  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const defaultGroupPolicy = resolveDefaultGroupPolicy(config as OpenClawConfig);
  const { groupPolicy, providerMissingFallbackApplied } =
    resolveAllowlistProviderRuntimeGroupPolicy({
      providerConfigPresent:
        ((config.channels as Record<string, unknown> | undefined)?.pulseboard ?? undefined) !==
        undefined,
      groupPolicy: account.config.groupPolicy as GroupPolicy | undefined,
      defaultGroupPolicy,
    });
  warnMissingProviderGroupPolicyFallbackOnce({
    providerMissingFallbackApplied,
    providerKey: CHANNEL_ID,
    accountId: account.accountId,
    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.room,
    log: (msg) => runtime.log?.(msg),
  });

  // Board-level allowlist check (groups only)
  let boardConfig = undefined;
  let wildcardConfig = undefined;
  if (isGroup) {
    const boardMatch = resolvePulseBoardBoardMatch({
      boards: account.config.boards,
      boardName: target,
    });
    if (!boardMatch.allowed) {
      runtime.log?.(`pulseboard: drop board ${target} (not allowlisted)`);
      return;
    }
    if (boardMatch.boardConfig?.enabled === false) {
      runtime.log?.(`pulseboard: drop board ${target} (disabled)`);
      return;
    }
    boardConfig = boardMatch.boardConfig;
    wildcardConfig = boardMatch.wildcardConfig;
  }

  // Resolve effective allow-from lists
  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);
  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
    provider: CHANNEL_ID,
    accountId: account.accountId,
    dmPolicy,
    readStore: pairing.readStoreForDmPolicy,
  });
  const storeAllowList = normalizePulseBoardAllowlist(storeAllowFrom);

  // Command gating flags
  const allowTextCommands = core.channel.commands.shouldHandleTextCommands({
    cfg: config as OpenClawConfig,
    surface: CHANNEL_ID,
  });
  const useAccessGroups =
    (config.commands as Record<string, unknown> | undefined)?.useAccessGroups !== false;
  const hasControlCommand = core.channel.text.hasControlCommand(rawBody, config as OpenClawConfig);

  // Access decision
  const configGroupAllowFrom = normalizePulseBoardAllowlist(account.config.groupAllowFrom);
  const access = resolveDmGroupAccessWithCommandGate({
    isGroup,
    dmPolicy,
    groupPolicy,
    allowFrom: configAllowFrom,
    groupAllowFrom: configGroupAllowFrom,
    storeAllowFrom: storeAllowList,
    isSenderAllowed: (allowFrom) => isPulseBoardSenderAllowed(senderId, allowFrom),
    command: {
      useAccessGroups,
      allowTextCommands,
      hasControlCommand,
    },
  });
  const commandAuthorized = access.commandAuthorized;

  if (isGroup) {
    if (access.decision !== "allow") {
      runtime.log?.(`pulseboard: drop board sender ${senderId} (reason=${access.reason})`);
      return;
    }
  } else {
    // DM access check
    if (access.decision !== "allow") {
      if (access.decision === "pairing") {
        await pairing.issueChallenge({
          senderId,
          senderIdLine: `Your PulseBoard user id: ${senderId}`,
          meta: { name: senderName || undefined },
          sendPairingReply: async (text) => {
            await sendMessagePulseBoard(`pulseboard:@${senderId}`, text, {
              accountId: account.accountId,
            });
            statusSink?.({ lastOutboundAt: Date.now() });
          },
          onReplyError: (err) => {
            runtime.error?.(
              `pulseboard: pairing reply failed for ${senderId}: ${String(err)}`,
            );
          },
        });
      }
      runtime.log?.(`pulseboard: drop DM sender ${senderId} (reason=${access.reason})`);
      return;
    }
  }

  if (access.shouldBlockControlCommand) {
    logInboundDrop({
      log: (msg) => runtime.log?.(msg),
      channel: CHANNEL_ID,
      reason: "control command (unauthorized)",
      target: senderId,
    });
    return;
  }

  // Mention gate (groups only)
  const mentionRegexes = core.channel.mentions.buildMentionRegexes(config as OpenClawConfig);
  const wasMentioned = mentionRegexes.length
    ? core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes)
    : false;
  const shouldRequireMention = isGroup
    ? resolvePulseBoardRequireMention({ boardConfig, wildcardConfig })
    : false;

  if (isGroup && shouldRequireMention && !wasMentioned && !hasControlCommand) {
    runtime.log?.(`pulseboard: drop board ${target} (no mention)`);
    return;
  }

  // Route resolution
  const route = core.channel.routing.resolveAgentRoute({
    cfg: config as OpenClawConfig,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    peer: {
      kind: isGroup ? "group" : "direct",
      id: isGroup ? target : senderId,
    },
  });

  // Build the inbound envelope
  const fromLabel = isGroup ? `board:${target}` : senderName || `user:${senderId}`;
  const storePath = core.channel.session.resolveStorePath(
    (config.session as Record<string, unknown> | undefined)?.store as string | undefined,
    { agentId: route.agentId },
  );
  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(
    config as OpenClawConfig,
  );
  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });
  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: fromLabel,
    timestamp: message.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const groupSystemPrompt = boardConfig?.systemPrompt?.trim() || undefined;

  // Finalize the inbound context payload
  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    BodyForAgent: rawBody,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: isGroup
      ? `pulseboard:board:${target}`
      : `pulseboard:@${senderId}`,
    To: isGroup ? `pulseboard:${target}` : `pulseboard:@${senderId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: isGroup ? "group" : "direct",
    ConversationLabel: fromLabel,
    SenderName: senderName || undefined,
    SenderId: senderId,
    GroupSubject: isGroup ? target : undefined,
    GroupSystemPrompt: isGroup ? groupSystemPrompt : undefined,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    WasMentioned: isGroup ? wasMentioned : undefined,
    MessageSid: message.messageId,
    Timestamp: message.timestamp,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: isGroup ? `pulseboard:${target}` : `pulseboard:@${senderId}`,
    CommandAuthorized: commandAuthorized,
  });

  // Record inbound session
  await core.channel.session.recordInboundSession({
    storePath,
    sessionKey: ctxPayload.SessionKey ?? route.sessionKey,
    ctx: ctxPayload,
    onRecordError: (err) => {
      runtime.error?.(`pulseboard: failed to record inbound session: ${String(err)}`);
    },
  });

  // Assemble the reply pipeline and deliver
  const { onModelSelected, ...replyPipeline } = createChannelReplyPipeline({
    cfg: config as OpenClawConfig,
    agentId: route.agentId,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });
  const deliver = createNormalizedOutboundDeliverer(async (payload) => {
    await deliverPulseBoardReply({
      payload,
      target: isGroup ? `pulseboard:${target}` : `pulseboard:@${senderId}`,
      accountId: account.accountId,
      statusSink,
    });
  });

  await dispatchReplyWithBufferedBlockDispatcher({
    ctx: ctxPayload,
    cfg: config as OpenClawConfig,
    dispatcherOptions: {
      ...replyPipeline,
      deliver,
      onError: (err, info) => {
        runtime.error?.(
          `pulseboard: dispatch error (${info.kind}): ${String(err)}`,
        );
      },
    },
    replyOptions: {
      onModelSelected,
    },
  });
}

