import type { ChannelSetupAdapter, ChannelSetupInput } from "openclaw/plugin-sdk/channel-setup";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/routing";
import {
  applyAccountNameToChannelSection,
  createSetupInputPresenceValidator,
  createTopLevelChannelDmPolicy,
  mergeAllowFromEntries,
  patchScopedAccountConfig,
  promptParsedAllowFromForAccount,
  resolveSetupAccountId,
  type ChannelSetupDmPolicy,
  type WizardPrompter,
} from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

type PulseBoardSetupInput = ChannelSetupInput & {
  baseUrl?: string;
  apiToken?: string;
  webhookSecret?: string;
};

export function normalizePulseBoardBaseUrl(value: string | undefined): string {
  return value?.trim().replace(/\/+$/, "") ?? "";
}

export function validatePulseBoardBaseUrl(value: string): string | undefined {
  if (!value) {
    return "Required";
  }
  if (!value.startsWith("http://") && !value.startsWith("https://")) {
    return "URL must start with http:// or https://";
  }
  return undefined;
}

export function setPulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  updates: Record<string, unknown>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: channel,
    accountId,
    patch: updates,
  }) as CoreConfig;
}

export function clearPulseBoardAccountFields(
  cfg: CoreConfig,
  accountId: string,
  fields: string[],
): CoreConfig {
  const section = cfg.channels?.pulseboard;
  if (!section) {
    return cfg;
  }

  if (accountId === DEFAULT_ACCOUNT_ID) {
    const nextSection = { ...section } as Record<string, unknown>;
    for (const field of fields) {
      delete nextSection[field];
    }
    return {
      ...cfg,
      channels: {
        ...(cfg.channels ?? {}),
        pulseboard: nextSection as typeof section,
      },
    } as CoreConfig;
  }

  const currentAccount = section.accounts?.[accountId];
  if (!currentAccount) {
    return cfg;
  }

  const nextAccount = { ...currentAccount } as Record<string, unknown>;
  for (const field of fields) {
    delete nextAccount[field];
  }
  return {
    ...cfg,
    channels: {
      ...(cfg.channels ?? {}),
      pulseboard: {
        ...section,
        accounts: {
          ...section.accounts,
          [accountId]: nextAccount as NonNullable<typeof section.accounts>[string],
        },
      },
    },
  } as CoreConfig;
}

async function promptPulseBoardAllowFrom(params: {
  cfg: CoreConfig;
  prompter: WizardPrompter;
  accountId: string;
}): Promise<CoreConfig> {
  return await promptParsedAllowFromForAccount({
    cfg: params.cfg,
    accountId: params.accountId,
    defaultAccountId: params.accountId,
    prompter: params.prompter,
    noteTitle: "PulseBoard user id",
    noteLines: [
      "1) Find user IDs in the PulseBoard admin panel or user profile page",
      "2) Or check the webhook payload logs when someone messages",
      "3) User IDs are typically lowercase usernames (without the @ prefix)",
      `Docs: ${formatDocsLink("/channels/pulseboard", "pulseboard")}`,
    ],
    message: "PulseBoard allowFrom (user id)",
    placeholder: "alice",
    parseEntries: (raw) => ({
      entries: String(raw)
        .split(/[\n,;]+/g)
        .map((value) => value.trim().replace(/^@/, "").toLowerCase())
        .filter(Boolean),
    }),
    getExistingAllowFrom: ({ cfg, accountId }) =>
      resolvePulseBoardAccount({ cfg, accountId }).config.allowFrom ?? [],
    mergeEntries: ({ existing, parsed }) =>
      mergeAllowFromEntries(
        existing.map((value) => String(value).trim().replace(/^@/, "").toLowerCase()),
        parsed,
      ),
    applyAllowFrom: ({ cfg, accountId, allowFrom }) =>
      setPulseBoardAccountConfig(cfg, accountId, {
        dmPolicy: "allowlist",
        allowFrom,
      }),
  });
}

async function promptPulseBoardAllowFromForAccount(params: {
  cfg: OpenClawConfig;
  prompter: WizardPrompter;
  accountId?: string;
}): Promise<OpenClawConfig> {
  const accountId = resolveSetupAccountId({
    accountId: params.accountId,
    defaultAccountId: resolveDefaultPulseBoardAccountId(params.cfg as CoreConfig),
  });
  return await promptPulseBoardAllowFrom({
    cfg: params.cfg as CoreConfig,
    prompter: params.prompter,
    accountId,
  });
}

export const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: `channels.${channel}.dmPolicy`,
  allowFromKey: `channels.${channel}.allowFrom`,
  getCurrent: (cfg) => cfg.channels?.[channel]?.dmPolicy ?? "pairing",
  promptAllowFrom: promptPulseBoardAllowFromForAccount,
});

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId),
  applyAccountName: ({ cfg, accountId, name }) =>
    applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name,
    }),
  validateInput: createSetupInputPresenceValidator({
    defaultAccountOnlyEnvError:
      "PULSEBOARD_API_TOKEN and PULSEBOARD_WEBHOOK_SECRET can only be used for the default account.",
    validate: ({ accountId: _accountId, input }) => {
      const setupInput = input as PulseBoardSetupInput;
      if (!setupInput.useEnv && !setupInput.apiToken) {
        return "PulseBoard requires --api-token (or --use-env with PULSEBOARD_API_TOKEN).";
      }
      if (!setupInput.useEnv && !setupInput.webhookSecret) {
        return "PulseBoard requires --webhook-secret (or --use-env with PULSEBOARD_WEBHOOK_SECRET).";
      }
      if (!setupInput.baseUrl) {
        return "PulseBoard requires --base-url.";
      }
      return null;
    },
  }),
  applyAccountConfig: ({ cfg, accountId, input }) => {
    const setupInput = input as PulseBoardSetupInput;
    const namedConfig = applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name: setupInput.name,
    });
    const next = setupInput.useEnv
      ? clearPulseBoardAccountFields(namedConfig as CoreConfig, accountId, [
          "apiToken",
          "webhookSecret",
        ])
      : namedConfig;
    const patch: Record<string, unknown> = {
      baseUrl: normalizePulseBoardBaseUrl(setupInput.baseUrl),
    };
    if (!setupInput.useEnv) {
      if (setupInput.apiToken) {
        patch.apiToken = setupInput.apiToken;
      }
      if (setupInput.webhookSecret) {
        patch.webhookSecret = setupInput.webhookSecret;
      }
    }
    return setPulseBoardAccountConfig(next as CoreConfig, accountId, patch);
  },
};

export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

