import type { ChannelSetupInput } from "openclaw/plugin-sdk/channel-setup";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createStandardChannelSetupStatus,
  formatDocsLink,
  setSetupChannelEnabled,
  type ChannelSetupWizard,
} from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./accounts.js";
import {
  clearPulseBoardAccountFields,
  normalizePulseBoardBaseUrl,
  pulseBoardDmPolicy,
  pulseBoardSetupAdapter,
  setPulseBoardAccountConfig,
  validatePulseBoardBaseUrl,
  listPulseBoardAccountIds,
} from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  stepOrder: "text-first",
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs setup",
    configuredHint: "configured",
    unconfiguredHint: "boards + DMs",
    configuredScore: 1,
    unconfiguredScore: 5,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some((accountId) => {
        const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        return Boolean(account.apiToken && account.webhookSecret && account.baseUrl);
      }),
  }),
  introNote: {
    title: "PulseBoard bot setup",
    lines: [
      "1) Log in to your PulseBoard admin panel",
      "2) Go to Settings > API Tokens and create a bot token",
      "3) Go to Settings > Webhooks and configure a webhook with a shared secret",
      "4) Note the server URL, API token, and webhook secret",
      "Tip: you can also set PULSEBOARD_API_TOKEN, PULSEBOARD_WEBHOOK_SECRET, and PULSEBOARD_BASE_URL in your env.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) => {
      const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
      return !account.apiToken || !account.webhookSecret || !account.baseUrl;
    },
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter: _prompter }) => {
    const resolvedAccount = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
    const hasEnvCreds = Boolean(
      process.env.PULSEBOARD_API_TOKEN?.trim() &&
      process.env.PULSEBOARD_WEBHOOK_SECRET?.trim() &&
      process.env.PULSEBOARD_BASE_URL?.trim(),
    );
    // Offer --use-env shortcut when all three env vars are present and for default account
    if (
      hasEnvCreds &&
      accountId === DEFAULT_ACCOUNT_ID &&
      !resolvedAccount.apiToken &&
      !resolvedAccount.baseUrl
    ) {
      return {
        credentialValues: {
          ...credentialValues,
          __useEnv: "1",
        },
      };
    }
    return undefined;
  },
  credentials: [
    {
      inputKey: "token",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "Enter PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const resolvedAccount = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        return {
          accountConfigured: Boolean(
            resolvedAccount.apiToken && resolvedAccount.webhookSecret && resolvedAccount.baseUrl,
          ),
          hasConfiguredValue: Boolean(resolvedAccount.config.apiToken),
          resolvedValue: resolvedAccount.apiToken || undefined,
          envValue:
            accountId === DEFAULT_ACCOUNT_ID
              ? process.env.PULSEBOARD_API_TOKEN?.trim() || undefined
              : undefined,
        };
      },
      applyUseEnv: async (params) => {
        const cleared = clearPulseBoardAccountFields(
          params.cfg as CoreConfig,
          params.accountId,
          ["apiToken"],
        );
        return setPulseBoardAccountConfig(cleared, params.accountId, {
          baseUrl: resolvePulseBoardAccount({ cfg: params.cfg as CoreConfig, accountId: params.accountId }).baseUrl,
        });
      },
      applySet: async (params) =>
        setPulseBoardAccountConfig(
          clearPulseBoardAccountFields(params.cfg as CoreConfig, params.accountId, ["apiToken"]),
          params.accountId,
          { apiToken: params.value },
        ),
    },
    {
      inputKey: "secret",
      providerHint: channel,
      credentialLabel: "webhook secret",
      preferredEnvVar: "PULSEBOARD_WEBHOOK_SECRET",
      envPrompt: "PULSEBOARD_WEBHOOK_SECRET detected. Use env var?",
      keepPrompt: "PulseBoard webhook secret already configured. Keep it?",
      inputPrompt: "Enter PulseBoard webhook secret",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const resolvedAccount = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        return {
          accountConfigured: Boolean(
            resolvedAccount.apiToken && resolvedAccount.webhookSecret && resolvedAccount.baseUrl,
          ),
          hasConfiguredValue: Boolean(resolvedAccount.config.webhookSecret),
          resolvedValue: resolvedAccount.webhookSecret || undefined,
          envValue:
            accountId === DEFAULT_ACCOUNT_ID
              ? process.env.PULSEBOARD_WEBHOOK_SECRET?.trim() || undefined
              : undefined,
        };
      },
      applyUseEnv: async (params) => {
        return clearPulseBoardAccountFields(
          params.cfg as CoreConfig,
          params.accountId,
          ["webhookSecret"],
        );
      },
      applySet: async (params) =>
        setPulseBoardAccountConfig(
          clearPulseBoardAccountFields(params.cfg as CoreConfig, params.accountId, [
            "webhookSecret",
          ]),
          params.accountId,
          { webhookSecret: params.value },
        ),
    },
  ],
  textInputs: [
    {
      inputKey: "httpUrl",
      message: "Enter PulseBoard server URL (e.g., https://pb.example.com)",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).baseUrl || undefined,
      shouldPrompt: ({ currentValue }) => !currentValue,
      validate: ({ value }) => validatePulseBoardBaseUrl(value),
      normalizeValue: ({ value }) => normalizePulseBoardBaseUrl(value),
      applySet: async (params) =>
        setPulseBoardAccountConfig(params.cfg as CoreConfig, params.accountId, {
          baseUrl: params.value,
        }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg: OpenClawConfig) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };

