import type { DmPolicy, GroupPolicy } from "../runtime-api.js";

export type { DmPolicy, GroupPolicy };

export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: { allow?: string[]; deny?: string[] };
  skills?: string[];
  enabled?: boolean;
  allowFrom?: string[];
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** Base URL of the PulseBoard server (e.g. "https://pb.example.com"). */
  baseUrl?: string;
  /** API token for outbound HTTP calls. */
  apiToken?: string;
  /** Shared secret for verifying inbound webhook HMAC-SHA256 signatures. */
  webhookSecret?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: string[];
  groupAllowFrom?: string[];
  groupPolicy?: GroupPolicy;
  /** Per-board configuration (key is board slug). */
  boards?: Record<string, PulseBoardBoardConfig>;
  webhookPort?: number;
  webhookHost?: string;
  webhookPath?: string;
  webhookPublicUrl?: string;
  historyLimit?: number;
  dmHistoryLimit?: number;
  dms?: Record<string, Record<string, unknown>>;
  textChunkLimit?: number;
  chunkMode?: "length" | "newline";
  blockStreaming?: boolean;
  blockStreamingCoalesce?: Record<string, unknown>;
  responsePrefix?: string;
  mediaMaxMb?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = {
  channels?: { pulseboard?: PulseBoardConfig };
  [key: string]: unknown;
};

/** Inbound webhook payload sent by the PulseBoard server. */
export type PulseBoardWebhookPayload = {
  messageId: string;
  chatType: "board" | "direct";
  boardName?: string | null;
  senderId: string;
  senderName: string;
  text: string;
  timestamp: number;
};

/** Normalized inbound message after parsing the webhook payload. */
export type PulseBoardInboundMessage = {
  messageId: string;
  isGroup: boolean;
  /** Board slug for groups; sender user ID for DMs. */
  target: string;
  senderId: string;
  senderName: string;
  text: string;
  timestamp: number;
};

/** Result of sending a message via the PulseBoard API. */
export type PulseBoardSendResult = {
  messageId: string;
  target: string;
};

