import { createHmac, timingSafeEqual } from "node:crypto";
import { createServer } from "node:http";
import type { IncomingMessage, Server, ServerResponse } from "node:http";
import {
  resolveLoggerBackedRuntime,
  z,
} from "../runtime-api.js";
import type { RuntimeEnv } from "../runtime-api.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type {
  CoreConfig,
  PulseBoardInboundMessage,
  PulseBoardWebhookPayload,
} from "./types.js";

const DEFAULT_WEBHOOK_PORT = 8789;
const DEFAULT_WEBHOOK_HOST = "0.0.0.0";
const DEFAULT_WEBHOOK_PATH = "/pulseboard-webhook";
const DEFAULT_WEBHOOK_MAX_BODY_BYTES = 512 * 1024;
const HEALTH_PATH = "/healthz";

const PulseBoardWebhookPayloadSchema: z.ZodType<PulseBoardWebhookPayload> = z.object({
  messageId: z.string().min(1),
  chatType: z.enum(["board", "direct"]),
  boardName: z.string().nullish(),
  senderId: z.string().min(1),
  senderName: z.string(),
  text: z.string(),
  timestamp: z.number(),
});

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/** Read the full request body, respecting a byte limit. */
async function readRequestBody(
  req: IncomingMessage,
  maxBytes: number,
): Promise<{ body: Buffer; limitExceeded: boolean }> {
  return new Promise((resolve) => {
    const chunks: Buffer[] = [];
    let total = 0;
    let limitExceeded = false;

    req.on("data", (chunk: Buffer) => {
      total += chunk.length;
      if (total > maxBytes) {
        limitExceeded = true;
        req.destroy();
        return;
      }
      chunks.push(chunk);
    });

    req.on("end", () => {
      resolve({ body: Buffer.concat(chunks), limitExceeded });
    });

    req.on("error", () => {
      resolve({ body: Buffer.concat(chunks), limitExceeded });
    });
  });
}

/** Verify the HMAC-SHA256 signature from the X-PulseBoard-Signature header. */
function verifyPulseBoardSignature(params: {
  rawBody: Buffer;
  signatureHeader: string | undefined;
  webhookSecret: string;
}): boolean {
  if (!params.signatureHeader) {
    return false;
  }
  const expected = createHmac("sha256", params.webhookSecret)
    .update(params.rawBody)
    .digest("hex");
  try {
    return timingSafeEqual(
      Buffer.from(params.signatureHeader, "utf8"),
      Buffer.from(expected, "utf8"),
    );
  } catch {
    return false;
  }
}

/** Map a parsed webhook payload to a normalized inbound message. */
function normalizeWebhookPayload(payload: PulseBoardWebhookPayload): PulseBoardInboundMessage {
  const isGroup = payload.chatType === "board";
  const target = isGroup ? (payload.boardName ?? payload.senderId) : payload.senderId;
  return {
    messageId: payload.messageId,
    isGroup,
    target,
    senderId: payload.senderId,
    senderName: payload.senderName,
    text: payload.text,
    timestamp: payload.timestamp,
  };
}

export function createPulseBoardWebhookServer(opts: {
  port: number;
  host: string;
  path: string;
  webhookSecret: string;
  onMessage: (message: PulseBoardInboundMessage) => void | Promise<void>;
  onError?: (error: Error) => void;
  abortSignal?: AbortSignal;
}): { server: Server; start: () => Promise<void>; stop: () => void } {
  const { port, host, path, webhookSecret, onMessage, onError, abortSignal } = opts;

  const server = createServer(async (req: IncomingMessage, res: ServerResponse) => {
    const url = req.url ?? "";

    // Health check endpoint
    if (url === HEALTH_PATH || url === `${HEALTH_PATH}/`) {
      res.writeHead(200, { "Content-Type": "text/plain" });
      res.end("ok");
      return;
    }

    if (url !== path && url !== `${path}/`) {
      res.writeHead(404, { "Content-Type": "text/plain" });
      res.end("Not Found");
      return;
    }

    if (req.method !== "POST") {
      res.writeHead(405, { "Content-Type": "text/plain" });
      res.end("Method Not Allowed");
      return;
    }

    const { body, limitExceeded } = await readRequestBody(req, DEFAULT_WEBHOOK_MAX_BODY_BYTES);
    if (limitExceeded) {
      res.writeHead(413, { "Content-Type": "text/plain" });
      res.end("Payload Too Large");
      return;
    }

    const signatureHeader =
      (req.headers["x-pulseboard-signature"] as string | undefined) ?? undefined;

    if (!verifyPulseBoardSignature({ rawBody: body, signatureHeader, webhookSecret })) {
      res.writeHead(401, { "Content-Type": "text/plain" });
      res.end("Invalid Signature");
      return;
    }

    let rawJson: unknown;
    try {
      rawJson = JSON.parse(body.toString("utf8"));
    } catch {
      res.writeHead(400, { "Content-Type": "text/plain" });
      res.end("Invalid JSON");
      return;
    }

    const parsed = PulseBoardWebhookPayloadSchema.safeParse(rawJson);
    if (!parsed.success) {
      res.writeHead(400, { "Content-Type": "text/plain" });
      res.end("Invalid Payload");
      return;
    }

    res.writeHead(200, { "Content-Type": "text/plain" });
    res.end("ok");

    // Dispatch inbound message asynchronously after responding
    const message = normalizeWebhookPayload(parsed.data);
    try {
      await onMessage(message);
    } catch (err) {
      onError?.(err instanceof Error ? err : new Error(formatError(err)));
    }
  });

  const start = (): Promise<void> =>
    new Promise((resolve, reject) => {
      server.once("error", reject);
      server.listen(port, host, () => {
        server.removeListener("error", reject);
        resolve();
      });
    });

  const stop = () => {
    server.closeAllConnections?.();
    server.close();
  };

  if (abortSignal) {
    abortSignal.addEventListener("abort", stop, { once: true });
  }

  return { server, start, stop };
}

export async function monitorPulseBoardProvider(opts: {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = (opts.config ?? core.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });
  const runtime = resolveLoggerBackedRuntime(
    opts.runtime,
    (msg) => core.logging.getChildLogger("pulseboard").info(msg),
  );

  const port = account.config.webhookPort ?? DEFAULT_WEBHOOK_PORT;
  const host = account.config.webhookHost ?? DEFAULT_WEBHOOK_HOST;
  const path = account.config.webhookPath ?? DEFAULT_WEBHOOK_PATH;

  const publicUrl =
    account.config.webhookPublicUrl ?? `http://${host === "0.0.0.0" ? "localhost" : host}:${port}${path}`;

  const webhookServer = createPulseBoardWebhookServer({
    port,
    host,
    path,
    webhookSecret: account.webhookSecret,
    abortSignal: opts.abortSignal,
    onMessage: async (message) => {
      // Record inbound activity
      try {
        core.channel.activity.record({
          channel: "pulseboard",
          accountId: account.accountId,
          direction: "inbound",
        });
      } catch {
        // runtime may not be initialized during tests
      }

      await handlePulseBoardInbound({
        message,
        account,
        config: cfg,
        runtime,
        statusSink: opts.statusSink,
      });
    },
    onError: (err) => {
      runtime.error?.(`[pulseboard:${account.accountId}] webhook handler error: ${err.message}`);
    },
  });

  await webhookServer.start();
  runtime.log?.(
    `[pulseboard:${account.accountId}] webhook server listening on ${publicUrl}`,
  );

  return { stop: webhookServer.stop };
}

