import type { CoreConfig, GroupPolicy, PulseBoardBoardConfig } from "./types.js";

export type BoardMatchResult = {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
  /** True when the board is explicitly listed or a wildcard `*` entry exists. */
  allowed: boolean;
};

/**
 * Resolve the board-specific config (exact match) and optional wildcard config
 * for a given board slug from the account's `boards` record.
 */
export function resolvePulseBoardBoardMatch(params: {
  boards?: Record<string, PulseBoardBoardConfig | undefined>;
  boardName: string;
}): BoardMatchResult {
  const { boards, boardName } = params;
  if (!boards || Object.keys(boards).length === 0) {
    return { allowed: false };
  }
  const wildcardConfig = boards["*"];
  const boardConfig = boards[boardName];
  // A board is allowed when it has an explicit entry OR a wildcard exists
  const allowed = boardConfig !== undefined || wildcardConfig !== undefined;
  return { boardConfig, wildcardConfig, allowed };
}

/**
 * Resolve whether a mention is required for a given board config.
 * Defaults to `true` when not explicitly configured (opt-in to responding).
 */
export function resolvePulseBoardRequireMention(params: {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
}): boolean {
  if (params.boardConfig?.requireMention !== undefined) {
    return params.boardConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  return true;
}

/**
 * Resolve the tool policy (allow/deny lists) for a given group/board,
 * merging board-level config over account defaults.
 */
export function resolvePulseBoardGroupToolPolicy(params: {
  cfg: CoreConfig;
  accountId?: string | null;
  groupId?: string | null;
}): { allow?: string[]; deny?: string[] } | undefined {
  const channelCfg = params.cfg.channels?.pulseboard;
  if (!channelCfg) {
    return undefined;
  }

  const accountId = params.accountId;
  const groupId = params.groupId;

  // Resolve the account config layer
  let accountCfg = channelCfg;
  if (accountId && accountId !== "default" && channelCfg.accounts?.[accountId]) {
    const merged = { ...channelCfg, ...channelCfg.accounts[accountId] };
    accountCfg = merged;
  }

  // Look for board-specific tool policy first
  if (groupId && accountCfg.boards) {
    const boardCfg = accountCfg.boards[groupId] ?? accountCfg.boards["*"];
    if (boardCfg?.tools) {
      return boardCfg.tools;
    }
  }

  return undefined;
}

/**
 * Normalize a PulseBoard allowFrom entry by stripping any known prefixes
 * and converting to lowercase.
 */
export function normalizePulseBoardAllowlistEntry(raw: string): string {
  return raw
    .trim()
    .replace(/^(pulseboard|pulse-board|pb):/i, "")
    .replace(/^@/, "")
    .toLowerCase();
}

/**
 * Normalize an array of PulseBoard allowFrom entries, filtering out empty values.
 */
export function normalizePulseBoardAllowlist(
  entries?: Array<string | number> | null,
): string[] {
  if (!entries) {
    return [];
  }
  return entries
    .map((entry) => normalizePulseBoardAllowlistEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Check whether a senderId is in the normalized allow list.
 * Supports `*` wildcard.
 */
export function isPulseBoardSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  if (allowFrom.length === 0) {
    return false;
  }
  const normalized = normalizePulseBoardAllowlistEntry(senderId);
  return allowFrom.some((entry) => entry === "*" || entry === normalized);
}

/** Resolve the effective group policy, defaulting to "allowlist" when not set. */
export function resolvePulseBoardGroupPolicy(
  groupPolicy?: GroupPolicy | string,
): GroupPolicy {
  if (groupPolicy === "open" || groupPolicy === "allowlist" || groupPolicy === "closed") {
    return groupPolicy;
  }
  return "allowlist";
}

