import { describeWebhookAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { formatAllowFromLowercase } from "openclaw/plugin-sdk/allow-from";
import {
  adaptScopedAccountAccessor,
  createScopedChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { createAccountStatusSink } from "openclaw/plugin-sdk/channel-lifecycle";
import {
  createLoggedPairingApprovalNotifier,
  createPairingPrefixStripper,
} from "openclaw/plugin-sdk/channel-pairing";
import { createAllowlistProviderRouteAllowlistWarningCollector } from "openclaw/plugin-sdk/channel-policy";
import {
  DEFAULT_ACCOUNT_ID,
  buildChannelConfigSchema,
  clearAccountEntryFields,
  createChatChannelPlugin,
} from "openclaw/plugin-sdk/core";
import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import {
  buildWebhookChannelStatusSummary,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
import type { ChannelPlugin, OpenClawConfig } from "../runtime-api.js";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
  type ResolvedPulseBoardAccount,
} from "./accounts.js";
import { PulseBoardConfigSchema } from "./config-schema.js";
import { monitorPulseBoardProvider } from "./monitor.js";
import {
  looksLikePulseBoardTargetId,
  normalizePulseBoardMessagingTarget,
} from "./normalize.js";
import { resolvePulseBoardGroupToolPolicy } from "./policy.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";
import { pulseBoardSetupWizard } from "./setup-surface.js";
import type { CoreConfig } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

const meta = {
  id: CHANNEL_ID,
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Boards + DMs)",
  docsPath: "/channels/pulseboard",
  docsLabel: "pulseboard",
  blurb: "Real-time bulletin board with named boards and direct messages.",
  aliases: ["pulse-board", "pb"],
  order: 70,
  quickstartAllowFrom: true,
};

const pulseBoardConfigAdapter = createScopedChannelConfigAdapter<
  ResolvedPulseBoardAccount,
  ResolvedPulseBoardAccount,
  CoreConfig
>({
  sectionKey: CHANNEL_ID,
  listAccountIds: listPulseBoardAccountIds,
  resolveAccount: adaptScopedAccountAccessor(resolvePulseBoardAccount),
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  clearBaseFields: ["apiToken", "webhookSecret", "baseUrl", "name"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    formatAllowFromLowercase({
      allowFrom,
      stripPrefixRe: /^(pulseboard|pulse-board|pb):/i,
    }),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: CHANNEL_ID,
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  normalizeEntry: (raw) =>
    raw
      .trim()
      .replace(/^(pulseboard|pulse-board|pb):/i, "")
      .replace(/^@/, "")
      .toLowerCase(),
});

const collectPulseBoardSecurityWarnings =
  createAllowlistProviderRouteAllowlistWarningCollector<ResolvedPulseBoardAccount>({
    providerConfigPresent: (cfg) =>
      (cfg.channels as Record<string, unknown> | undefined)?.[CHANNEL_ID] !== undefined,
    resolveGroupPolicy: (account) => account.config.groupPolicy,
    resolveRouteAllowlistConfigured: (account) =>
      Boolean(account.config.boards) && Object.keys(account.config.boards ?? {}).length > 0,
    restrictSenders: {
      surface: "PulseBoard boards",
      openScope: "any member in allowed boards",
      groupPolicyPath: `channels.${CHANNEL_ID}.groupPolicy`,
      groupAllowFromPath: `channels.${CHANNEL_ID}.groupAllowFrom`,
    },
    noRouteAllowlist: {
      surface: "PulseBoard boards",
      routeAllowlistPath: `channels.${CHANNEL_ID}.boards`,
      routeScope: "board",
      groupPolicyPath: `channels.${CHANNEL_ID}.groupPolicy`,
      groupAllowFromPath: `channels.${CHANNEL_ID}.groupAllowFrom`,
    },
  });

function isPulseBoardConfigured(account: ResolvedPulseBoardAccount): boolean {
  return Boolean(account.apiToken && account.webhookSecret && account.baseUrl);
}

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: CHANNEL_ID,
      meta,
      setupWizard: pulseBoardSetupWizard,
      capabilities: {
        chatTypes: ["direct", "group"],
        reactions: false,
        threads: false,
        media: true,
        nativeCommands: false,
        blockStreaming: true,
      },
      reload: { configPrefixes: [`channels.${CHANNEL_ID}`] },
      configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
      config: {
        ...pulseBoardConfigAdapter,
        isConfigured: isPulseBoardConfigured,
        describeAccount: (account) =>
          describeWebhookAccountSnapshot({
            account,
            configured: isPulseBoardConfigured(account),
            extra: {
              apiTokenSource: account.apiTokenSource,
              webhookSecretSource: account.webhookSecretSource,
              baseUrl: account.baseUrl ? "[set]" : "[missing]",
            },
          }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
          const boards = account.config.boards;
          if (!boards || !groupId) {
            return true;
          }
          const boardConfig = boards[groupId];
          if (boardConfig?.requireMention !== undefined) {
            return boardConfig.requireMention;
          }
          const wildcardConfig = boards["*"];
          if (wildcardConfig?.requireMention !== undefined) {
            return wildcardConfig.requireMention;
          }
          return true;
        },
        resolveToolPolicy: (params) =>
          resolvePulseBoardGroupToolPolicy(params as { cfg: CoreConfig; accountId?: string | null; groupId?: string | null }),
      },
      messaging: {
        normalizeTarget: normalizePulseBoardMessagingTarget,
        targetResolver: {
          looksLikeId: looksLikePulseBoardTargetId,
          hint: "<boardName | @userId>",
        },
      },
      setup: pulseBoardSetupAdapter,
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ snapshot }) =>
          buildWebhookChannelStatusSummary(snapshot, {
            apiTokenSource: (snapshot as Record<string, unknown>).apiTokenSource ?? "none",
            webhookSecretSource:
              (snapshot as Record<string, unknown>).webhookSecretSource ?? "none",
          }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: isPulseBoardConfigured(account),
          extra: {
            apiTokenSource: account.apiTokenSource,
            webhookSecretSource: account.webhookSecretSource,
            baseUrl: account.baseUrl ? "[set]" : "[missing]",
            mode: "webhook",
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          if (!isPulseBoardConfigured(account)) {
            throw new Error(
              `PulseBoard not configured for account "${account.accountId}" (missing apiToken, webhookSecret, or baseUrl)`,
            );
          }

          ctx.log?.info(`[${account.accountId}] starting PulseBoard webhook server`);

          const statusSink = createAccountStatusSink({
            accountId: ctx.accountId,
            setStatus: ctx.setStatus,
          });

          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () =>
              await monitorPulseBoardProvider({
                accountId: account.accountId,
                config: ctx.cfg as CoreConfig,
                runtime: ctx.runtime,
                abortSignal: ctx.abortSignal,
                statusSink,
              }),
          });
        },
        logoutAccount: async ({ accountId, cfg }) => {
          const nextCfg = { ...cfg } as OpenClawConfig;
          const nextSection = cfg.channels?.[CHANNEL_ID]
            ? { ...cfg.channels[CHANNEL_ID] }
            : undefined;
          let cleared = false;
          let changed = false;

          if (nextSection) {
            if (accountId === DEFAULT_ACCOUNT_ID && (nextSection as Record<string, unknown>).apiToken) {
              delete (nextSection as Record<string, unknown>).apiToken;
              cleared = true;
              changed = true;
            }
            if (accountId === DEFAULT_ACCOUNT_ID && (nextSection as Record<string, unknown>).webhookSecret) {
              delete (nextSection as Record<string, unknown>).webhookSecret;
              cleared = true;
              changed = true;
            }
            const accountCleanup = clearAccountEntryFields({
              accounts: (nextSection as Record<string, unknown>).accounts as Record<string, unknown> | undefined,
              accountId,
              fields: ["apiToken", "webhookSecret"],
            });
            if (accountCleanup.changed) {
              changed = true;
              if (accountCleanup.cleared) {
                cleared = true;
              }
              if (accountCleanup.nextAccounts) {
                (nextSection as Record<string, unknown>).accounts = accountCleanup.nextAccounts as Record<string, object>;
              } else {
                delete (nextSection as Record<string, unknown>).accounts;
              }
            }
          }

          if (changed) {
            if (nextSection && Object.keys(nextSection).length > 0) {
              nextCfg.channels = {
                ...nextCfg.channels,
                [CHANNEL_ID]: nextSection as NonNullable<OpenClawConfig["channels"]>[typeof CHANNEL_ID],
              };
            } else {
              const nextChannels = { ...nextCfg.channels } as Record<string, unknown>;
              delete nextChannels[CHANNEL_ID];
              if (Object.keys(nextChannels).length > 0) {
                nextCfg.channels = nextChannels as OpenClawConfig["channels"];
              } else {
                delete nextCfg.channels;
              }
            }
          }

          const resolved = resolvePulseBoardAccount({
            cfg: changed ? (nextCfg as CoreConfig) : (cfg as CoreConfig),
            accountId,
          });
          const loggedOut = resolved.apiTokenSource === "none";

          if (changed) {
            await getPulseBoardRuntime().config.writeConfigFile(nextCfg);
          }

          return {
            cleared,
            envApiToken: Boolean(process.env.PULSEBOARD_API_TOKEN?.trim()),
            loggedOut,
          };
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUserId",
        message: "OpenClaw: your access has been approved.",
        normalizeAllowEntry: createPairingPrefixStripper(
          /^(pulseboard|pulse-board|pb):/i,
          (entry) => entry.replace(/^@/, "").toLowerCase(),
        ),
        notify: createLoggedPairingApprovalNotifier(
          ({ id }) => `[pulseboard] User ${id} approved for pairing`,
        ),
      },
    },
    security: {
      resolveDmPolicy: resolvePulseBoardDmPolicy,
      collectWarnings: collectPulseBoardSecurityWarnings,
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: (text, limit) =>
          getPulseBoardRuntime().channel.text.chunkMarkdownText(text, limit),
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: CHANNEL_ID,
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, text, {
            accountId: accountId ?? undefined,
            replyTo: replyToId ?? undefined,
            cfg: cfg as CoreConfig,
          }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          await sendMessagePulseBoard(
            to,
            mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            {
              accountId: accountId ?? undefined,
              replyTo: replyToId ?? undefined,
              cfg: cfg as CoreConfig,
            },
          ),
      },
    },
  });
